import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"内力","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/内力.md","filePath":"4.资源分区/5.能量池/内力.md"}'),d={name:"4.资源分区/5.能量池/内力.md"};function b(l,e,p,i,_,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"内力",tabindex:"-1"},[s("内力 "),r("a",{class:"header-anchor",href:"#内力","aria-label":'Permalink to "内力"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序009")])])],-1),o('<h1 id="内力-1" tabindex="-1">内力 <a class="header-anchor" href="#内力-1" aria-label="Permalink to &quot;内力&quot;">​</a></h1><p>内力<br> 内力是一种东方能量池，其性质中正平和，作用虽不较气、斗气、电磁力等能量在攻击上来的刚猛霸道，却胜在效用全面，也是催动大多数东方技艺所需要的能量。</p><p>无名内功<br> 500<br> 强化后开启内力能量池，其关键属性为感知+耐力。<br> 内力的基础恢复方式为：<br> 1、在一次至少十五分钟的短休息中打坐运转内力穿行经络循环小周天，进行一个内力关键属性检定，恢复成功数点内力。<br> 2、花费8小时时间打坐运转内力循环大周天，恢复内力能量池上限的内力，这同时视为你进行了一次长休息。<br> 强化者一日恢复的内力上限为能量池上限的三倍。</p><p>基础内功<br> D+500<br> 此等级的内功仅是给予强化者粗略运用内力的门道。<br> 前提：具有内力能量池<br> 强化后开启内力的基础用法：<br> 【益体】：自由动作支付2点内力增强身体素质，使用者的生理属性在一场景内均获得1点能量加值。<br> 【护身】：受到攻击时，可消耗1点内力将1点严重伤害转化为冲击点数。<br> 【调捋】：消耗1点内力，你可以将正常人的一种生理周期（吃/喝/睡）延后十二小时，每种周期在三日内至多延后能量池等级次。<br> 【止血】：使用者可以迅捷动作消耗1点内力将不断恶化的伤口延缓恶化1轮，此能力可以对触及范围内的其他人使用，一场景内至多使用能量池等级+1次。<br> 【疗伤】：使用者在打坐运转小周天完毕后，可同时将关键属性检定成功数的严重伤害转化为完好。一日内此用法恢复的生命值不能超过能量池上限。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=a(d,[["render",b]]);export{f as __pageData,m as default};
